var e=[{id:`L2_1`,type:`dialog`,speaker:`LARA_NPC_NULL_NULL`,text:{KOREA:`흐흥흥~ 다음 배달지로 출발해 볼까나?`,JPN:`フンフフ～ン♪　次のお届け先に出発しようかな？`,ENG:`La, la, la. Let's go to the next delivery address.`,TWN:`呵呵呵～出發前往下一個配送地點吧？`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`…….`,JPN:`……`,ENG:`…`,TWN:`…`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`AMY_NPC_FOOLSDAY_QM`,text:{KOREA:`지금이다!`,JPN:`今だ！`,ENG:`Now!`,TWN:`趁現在！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LARA_NPC_NULL_NULL`,text:{KOREA:`우앗?! 줄이 발에 걸렸다…?!`,JPN:`わっ！？　足に紐が引っかかった……！？`,ENG:`Wah! I tripped over a string...?`,TWN:`啊咧？！腳絆到繩子…？！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`AMY_NPC_FOOLSDAY_QM`,text:{KOREA:`헤헤, 드디어 잡았다.`,JPN:`ヘヘッ、やっと捕まえた。`,ENG:`Heh heh! Finally, we got you!`,TWN:`嘿嘿，終於抓到了吧！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_PRIDE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LARA_NPC_NULL_NULL`,text:{KOREA:`응?`,JPN:`え？`,ENG:`Huh?`,TWN:`嗯？`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LARA_NPC_NULL_NULL`,text:{KOREA:`꺄아아! 야한 그림체를 가진 요요를 휘두르는 해적이다!`,JPN:`きゃー！　ヨーヨーを振り回すエロい絵柄の海賊だ！`,ENG:`Kyaaak! A pirate swinging a yoyo with a lewd art style on it!`,TWN:`哇啊啊！是玩溜溜球的海盜！而且溜溜球上還有色情圖片！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_HATE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`LEEJISOONPC_NPC_FOOLSDAY_QM`,text:{KOREA:`해적은 아니고 공무원이야.`,JPN:`海賊ではなく、公務員だ。`,ENG:`I'm not a pirate. I'm a government official.`,TWN:`我是不是海盜，是公務員。`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_HATE`},C:null,R:{char_id:`LEEJISOONPC_NPC_FOOLSDAY_QM`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`LARA_NPC_NULL_NULL`,text:{KOREA:`어라, 두 사람? 당신들은 누구시죠?`,JPN:`あれ、二人も？　どちら様ですか？`,ENG:`Err, you two. Who are you?`,TWN:`嗯？是平行時空嗎？你們是誰？`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`AMY_NPC_FOOLSDAY_QM`,text:{KOREA:`훗, 우리가 누구냐고 물으신다면…`,JPN:`ふふ、なんだかんだと聞かれたら……`,ENG:`Heh, prepare for trouble.`,TWN:`呵，既然你誠心誠意地發問了…`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:null,C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`AMY_NPC_FOOLSDAY_QM`,text:{KOREA:`우주의 평화를 지키는…!`,JPN:`この宇宙の平和を守る……！`,ENG:`To protect the world from devastation...!`,TWN:`為了守護宇宙的和平…！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_LAUGH`},C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,text:{KOREA:`외우주 통합질서 특수 검거반 6팀 L 그리고 A다.`,JPN:`外宇宙総合秩序特殊捜査課6班のM、そしてAだ。`,ENG:`L and A Of Outer Space United Order Special Police Team 6.`,TWN:`為了維護外太空的秩序，我們是特殊刑警大隊第6小隊的L和A！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_LAUGH`},C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,text:{KOREA:`당신을 체포하러 왔어.`,JPN:`お前を逮捕しに来た。`,ENG:`We came to arrest you.`,TWN:`我們是來逮捕你的！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:{char_id:`AMY_NPC_FOOLSDAY_QM`,face:`UNIT_IDLE`},C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,face:`UNIT_IDLE`}}}},{id:`L30_1`,type:`dialog`,speaker:`AMY_NPC_FOOLSDAY_NAMED`,text:{KOREA:`야 야, 제일 재밌는 부분인데 그렇게 평범하게 소개하면 어떡해?`,JPN:`ちょっとちょっと、一番肝心なところなのにそんな地味な紹介でいいわけ？`,ENG:`Hey! That was the funniest part, and you ruined it by saying it in such a monotone.`,TWN:`喂喂喂，這段是最精彩的部分欸，怎麼被你介紹得那麼雞肋？`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:{char_id:`AMY_NPC_FOOLSDAY_NAMED`,face:`UNIT_SERIOUS`},C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,face:`UNIT_IDLE`}}}},{id:`L31_1`,type:`dialog`,speaker:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,text:{KOREA:`질질 끌면 아이스크림 녹아. 빨리 하고 끝내.`,JPN:`ダラダラするとアイスクリームが溶けてしまう。さっさと終わらせよう。`,ENG:`Let's not drag on. The ice cream is melting. Let's get this over with.`,TWN:`再這樣拖拖拉拉的，冰淇淋都要融化了，趕快搞定吧！`},stage:{bg:`COUNTERSIDE_SPACE`,slots:{L:{char_id:`AMY_NPC_FOOLSDAY_NAMED`,face:`UNIT_SERIOUS`},C:{char_id:`LARA_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`LEEJISOONPC_NPC_FOOLSDAY_NAMED`,face:`UNIT_IDLE`}}}}];export{e as default};